script:
frappe.ui.form.on('Supplier', {
    custom_gstin: function(frm) {
        var gstin = (frm.doc.custom_gstin || '').trim().toUpperCase();
        if (!gstin) return;
        var re = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}Z[0-9A-Z]{1}$/;
        if (!re.test(gstin)) {
            frappe.msgprint({title:'Invalid GSTIN', message:'GSTIN must be 15 characters: 22AAAAA0000A1Z5', indicator:'red'});
            frm.set_value('custom_gstin', '');
            return;
        }
        frm.set_value('custom_gstin', gstin);
        if (!frm.doc.tax_id) frm.set_value('tax_id', gstin);
        frappe.show_alert({message:'✓ Valid GSTIN', indicator:'green'}, 3);
        if (frm.doc.custom_msme_reg_no) {
            frappe.show_alert({message:'MSME supplier — 45-day payment rule applies', indicator:'orange'}, 4);
        }
    },
    validate: function(frm) {
        var gstin = (frm.doc.custom_gstin || '').trim();
        if (!gstin) return;
        var re = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}Z[0-9A-Z]{1}$/;
        if (!re.test(gstin)) frappe.throw('Invalid GSTIN format.');
    }
});
